document.addEventListener("DOMContentLoaded",()=>{const t=document.getElementById("languageBtn"),e=document.getElementById("languageList"),o=document.getElementById("arrowIcon");t.addEventListener("click",()=>{toggleDropdown(e,o)}),document.addEventListener("click",n=>{t.contains(n.target)||e.contains(n.target)||closeDropdown(e,o)}),document.addEventListener("keydown",n=>{n.key==="Escape"&&closeDropdown(e,o)})});var toggleDropdown=(t,e)=>{t.classList.contains("open")?closeDropdown(t,e):(t.classList.add("open"),e.classList.add("rotate"))},closeDropdown=(t,e)=>{t.classList.remove("open"),e.classList.remove("rotate")};
